109: const TimelineCardHeaderButton = ({ room, isHighlighted, onClick }: IHeaderButtonProps) => {
110:     let unreadIndicator;
111:     const color = RoomNotificationStateStore.instance.getRoomState(room).color;
112:     switch (color) {
113:         case NotificationColor.Bold:
114:         case NotificationColor.Grey:
115:         case NotificationColor.Red:
116:             unreadIndicator = <UnreadIndicator color={color} />;
117:     }
118:     return <HeaderButton
119:         name="timelineCardButton"
120:         title={_t("Chat")}
121:         isHighlighted={isHighlighted}
122:         onClick={onClick}
123:     >
124:         { unreadIndicator }
125:     </HeaderButton>;
126: };
